import{gt as e,nt as t,s as n,tt as r}from"./chunks/framework.BqU7tCwc.js";var i=JSON.parse(`{"title":"giffgaff eSIM 开通与保号记录","description":"","frontmatter":{"title":"giffgaff eSIM 开通与保号记录"},"headers":[],"relativePath":"other/giffgaff.md","filePath":"other/giffgaff.md","lastUpdated":1784882697000}`),a={name:`other/giffgaff.md`};function o(n,i,a,o,s,c){return e(),r(`div`,null,[...i[0]||=[t(`<h1 id="giffgaff-esim-开通与保号记录" tabindex="-1">giffgaff eSIM 开通与保号记录 <a class="header-anchor" href="#giffgaff-esim-开通与保号记录" aria-label="Permalink to “giffgaff eSIM 开通与保号记录”">​</a></h1><p>本文整理自一套 Android 设备上的实操记录：通过可写入 eSIM 的实体卡安装 giffgaff eSIM。它不是 giffgaff 的官方操作指南，也不保证适用于所有手机、eSIM 卡或地区。</p><blockquote><p>第三方 APK、写卡操作和运营商规则都有风险。安装前应确认来源、校验文件完整性，并自行承担兼容性和账户风险；套餐、充值金额、保号条件及可用性以 <a href="https://www.giffgaff.com/" target="_blank" rel="noreferrer">giffgaff 官网</a> 和 <a href="https://www.giffgaff.com/terms" target="_blank" rel="noreferrer">官方条款</a> 为准。</p></blockquote><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to “前置条件”">​</a></h2><ul><li>Android 手机。</li><li>一张支持写入 eSIM 的实体卡；原始记录使用 <code>estkme</code>。</li><li>可用于支付的 Visa 或 MasterCard 银行卡。</li></ul><h2 id="工具与下载地址" tabindex="-1">工具与下载地址 <a class="header-anchor" href="#工具与下载地址" aria-label="Permalink to “工具与下载地址”">​</a></h2><p>下列工具均来自原始记录。其中 giffgaff Android 安装包链接为第三方分发页，优先选择官方应用商店或 giffgaff 官方提供的安装方式。</p><table tabindex="0"><thead><tr><th>工具</th><th>用途</th><th>链接</th></tr></thead><tbody><tr><td>元萝卜</td><td>用于从管理器安装其他 APK</td><td><a href="https://www.die.lu/" target="_blank" rel="noreferrer">下载页</a> · <a href="https://github.com/Katana-Official/SPatch-Update" target="_blank" rel="noreferrer">SPatch-Update</a></td></tr><tr><td>Via 浏览器</td><td>注册与访问网页时使用</td><td><a href="https://viayoo.com/zh-cn/" target="_blank" rel="noreferrer">官网</a> · <a href="https://res.viayoo.com/v1/via-release-cn.apk" target="_blank" rel="noreferrer">APK</a></td></tr><tr><td>HookEuicc</td><td>原始记录中用于伪装 eSIM 支持并取得激活码</td><td><a href="https://github.com/Unicorn369/HookEuicc" target="_blank" rel="noreferrer">GitHub</a></td></tr><tr><td>giffgaff</td><td>官方运营商应用</td><td><a href="https://mi9.com/package/com.giffgaffmobile.controller/" target="_blank" rel="noreferrer">第三方 APK 页面</a></td></tr><tr><td>小叮当个人博客</td><td>原始视频演示的补充参考</td><td><a href="https://techbigding.top/" target="_blank" rel="noreferrer">techbigding.top</a></td></tr></tbody></table><h2 id="开通流程" tabindex="-1">开通流程 <a class="header-anchor" href="#开通流程" aria-label="Permalink to “开通流程”">​</a></h2><h3 id="_1-注册-giffgaff-账户" tabindex="-1">1. 注册 giffgaff 账户 <a class="header-anchor" href="#_1-注册-giffgaff-账户" aria-label="Permalink to “1. 注册 giffgaff 账户”">​</a></h3><p>访问 <a href="https://www.giffgaff.com/" target="_blank" rel="noreferrer">giffgaff 官网</a> 并按页面提示注册。可使用网页或官方应用完成；支付、实名与地区要求以注册时页面为准。</p><h3 id="_2-安装所需环境" tabindex="-1">2. 安装所需环境 <a class="header-anchor" href="#_2-安装所需环境" aria-label="Permalink to “2. 安装所需环境”">​</a></h3><ol><li>直接安装元萝卜 APK。</li><li>在元萝卜中依次进入“配置” → “从管理器安装软体”，选择并安装 giffgaff、Via 浏览器和 HookEuicc 的 APK。</li><li>在 HookEuicc 中开启伪装功能；若应用提示异常，可按原始记录尝试关闭后重新打开。</li></ol><h3 id="_3-购买-esim" tabindex="-1">3. 购买 eSIM <a class="header-anchor" href="#_3-购买-esim" aria-label="Permalink to “3. 购买 eSIM”">​</a></h3><p>在 giffgaff 的下单流程中选择 eSIM。原始记录的做法是暂不选择套餐、先充值 <code>10</code> 欧元完成开通；该金额、可选套餐和支付条件可能变动，应以结算页显示为准。</p><h3 id="_4-获取并写入-esim" tabindex="-1">4. 获取并写入 eSIM <a class="header-anchor" href="#_4-获取并写入-esim" aria-label="Permalink to “4. 获取并写入 eSIM”">​</a></h3><ol><li>在 giffgaff 中选择 <code>Install eSIM</code>，按提示取得激活字符串。</li><li>复制该字符串。</li><li>在 eSIM 卡管理工具中添加该激活信息，并按工具提示完成写入。</li></ol><p>写入前确认实体 eSIM 卡有可用空间；写入后可在手机网络设置中检查是否识别到 giffgaff 配置文件。若无法激活，不要反复尝试写入，应先确认设备、eSIM 卡和账号状态是否兼容。</p><h2 id="保号" tabindex="-1">保号 <a class="header-anchor" href="#保号" aria-label="Permalink to “保号”">​</a></h2><p>原始记录写明：每 <code>180</code> 天内让账户余额发生一次变动（消费或充值），可延长 <code>180</code> 天。可采用的方式包括：</p><ul><li>发送一条短信；</li><li>使用一次移动数据；</li><li>拨打一通电话（不含紧急服务和官方客服热线）；</li><li>充值一次话费。</li></ul><p>这项规则可能随运营商政策调整。执行保号前请通过 giffgaff 账户、帮助中心或客服确认当前失效周期和有效活动定义。</p><h2 id="常用入口" tabindex="-1">常用入口 <a class="header-anchor" href="#常用入口" aria-label="Permalink to “常用入口”">​</a></h2><ul><li><a href="https://www.giffgaff.com/top-up" target="_blank" rel="noreferrer">充值</a></li><li><a href="https://www.giffgaff.com/profile/usage-statement" target="_blank" rel="noreferrer">话费与账单查询</a></li><li><a href="https://help.giffgaff.com/en/collections/626993-esim" target="_blank" rel="noreferrer">eSIM 帮助中心</a></li><li><a href="https://github.com/ssnhd/sim" target="_blank" rel="noreferrer">补卡工具</a></li><li><a href="https://www.giffgaff.com/profile/details#simswap" target="_blank" rel="noreferrer">转入空卡（SIM Swap）</a></li><li><a href="https://help.giffgaff.com/en/articles/258841-wifi-calling-and-volte" target="_blank" rel="noreferrer">Wi-Fi Calling 与 VoLTE</a></li><li><a href="https://www.giffgaff.com/boiler-plate/contact" target="_blank" rel="noreferrer">官方客服</a></li><li><a href="https://www.giffgaff.com/terms" target="_blank" rel="noreferrer">官方条款</a></li></ul>`,24)]])}var s=n(a,[[`render`,o]]);export{i as __pageData,s as default};